/* <flatten type="Javascript"> */
function load$GridVoucherDetail$(g) {
  g.add_itemValueChanged(onChange$GridVoucherDetail$);
  g.add_onResponseComplete(on$GridVoucherDetail$ResponseComplete);
  g.add_commandEvent(on$GridVoucherDetail$ExecuteCommand);
  g.$a = {t_so_luong: ['t_so_luong', 'so_luong']};
  g.$h = [['voucherCode', 'String', g._voucherCode], 'ma_dvcs'];
  udf$Detail$(g);
}
function dispose$GridVoucherDetail$(g) {
  g.$a = null;
  try {g.remove_commandEvent(on$GridVoucherDetail$ExecuteCommand);} catch (ex) {}
  try {g.remove_itemValueChanged(onChange$GridVoucherDetail$);} catch (ex) {}
  try {g.remove_onResponseComplete(on$GridVoucherDetail$ResponseComplete);} catch (ex) {}
}
function onChange$GridVoucherDetail$(sender, eventArgs) {
  var o = eventArgs.get_object(), g = o.grid, f = g.get_element().parentForm, name = o.field.Name;
  switch (name) {
    case 'so_luong':
      g.validExpression(o, null, [g.$a.t_so_luong]);
      break;
    default:
      break;
  }
}
function on$GridVoucherDetail$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, f = g.get_element().parentForm;
  switch (action) {
    case 'AfterRemoveRow':
      on$GridVoucherDetail$RowChange(g, f);
      break;
    case 'AfterCloneRow':
      g.setItemFieldValue('stt_rec0', e.type.Value, '');
      on$GridVoucherDetail$RowChange(g, f);
      break;
    case 'Check':
      g.validRowExpression('ma_vi_tri', '([vi_tri_yn] == 0) || ([ma_vi_tri] != "")');
      break;
    case 'Retrieve':
      if (f._action == 'View') break;
      if (!f.validFields('ma_kh, ngay_ct')) break;
      g.showForm('MOOrderFilter');
      break;
    case 'Copying':
      set$Voucher$EmptyExternalField(g, 'dh_so, dh_ln, stt_rec_dh, stt_rec0dh');
      break;
    default:
      break;
  }
}
function on$GridVoucherDetail$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object, f = g.get_element().parentForm;
  switch (context) {
    case 'Item':
      var v = (result[0].Value == '' ? true : null), t = (result[0].Value == '' ? 'false' : 'true');
      g.setItemGridBehavior(o, [
        ['ma_kho', result[0].Value, '', true],
        ['ma_vi_tri', result[1].Value, '', v],
        ['dvt', result[2].Value, '', true],
        ['he_so', result[3].Value, null, null],
        ['vi_tri_yn', [result[4].Value, t], null, null],
        ['lo_yn', result[5].Value, null, null]
      ]);
      g.live(o, 'dvt');
      break;
    case 'UOM':
      g.setItemGridBehavior(o, [['he_so', result[0].Value, null, true]]);
      break;
    case 'Site':
      g.setItemGridBehavior(o, [['ma_vi_tri', '', '', null], ['vi_tri_yn', result[0].Value, null, null]]);
      break;
    default:
      break;
  }
}
function onChange$GridVoucherDetail$Item(o) {o.grid.request(o, 'Item', 'Item', ['ma_vt'], o.grid.$h, true);}
function onChange$GridVoucherDetail$UOM(o) {o.grid.request(o, 'UOM', 'UOM', ['ma_vt', 'dvt'], null, true);}
function onChange$GridVoucherDetail$Site(o) {o.grid.request(o, 'Site', 'Site', ['ma_kho', 'ma_vt'], o.grid.$h, true);}
function on$GridVoucherDetail$RowChange(g, f) {g.executeAggregate([g.$a.t_so_luong]);}
/* </flatten> */

      &ScriptInsertRetrieveItems;
      &ScriptEmptyExternalField;

grid.response:
&XMLGetUOMConversion;
if exists(select 1 from dmvt where ma_vt = @ma_vt) begin declare @unitCode varchar(32) select @unitCode = case when @$ma_dvcs = '' then @@unit else @$ma_dvcs end exec FastBusiness$Voucher$MO$Item @unitCode, @ma_vt, @voucherCode, @@userID, @@admin return end
declare @unitCode varchar(32) select @unitCode = case when @$ma_dvcs = '' then @@unit else @$ma_dvcs end if exists(select 1 from dmkho where ma_kho = @ma_kho and ma_dvcs = @unitCode&SiteCheck;) begin select case when exists(select 1 from dmvitri where dmvitri.ma_kho = @ma_kho) then 1 else 0 end as vi_tri_yn return end
